#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005,M=8000005;
int n,m,dfn[N],cnt,siz[N],f[N][25],block,dep[N],ans[M];
int qcnt,a[N],root,b[N],num[N],cntl[N],cntr[N],cnt2,sum;
//cntl[i]:莫队中执行到的1~l部分 i 的出现次数 
//cntr同理
//num[i]表示dfn为i的点的点权
vector<int> g[N];
int fun(int x)
{
	return (x-1)/block+1;
}
struct node
{
	int l,r,id;
	bool operator<(const node other) const
	{
		if(fun(other.l)==fun(l)) return r<other.r;
		return l<other.l;
	}
} q[M];
void dfs(int u,int fa)
{
	dfn[u]=++cnt;
	siz[u]=1;
	dep[u]=dep[fa]+1;
	f[u][0]=fa;
	for(int i=1;i<=log2(n);i++)
	{
		if(f[f[u][i-1]][i-1]==0) continue;
		f[u][i]=f[f[u][i-1]][i-1];
	}
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==fa) continue;
		dfs(v,u);
		siz[u]+=siz[v];
	}
}
void add(int l,int r,int lll,int rr,int i)
{
	q[++qcnt]=node{r,rr,i};
	q[++qcnt]=node{l-1,rr,-i}; 
	q[++qcnt]=node{lll-1,r,-i};
	q[++qcnt]=node{l-1,lll-1,i};
}
int up(int x,int y)
{
	for(int i=log2(n);i>=0;i--)
	{
		if(y>=(1<<i))
		{
			y-=(1<<i);
			x=f[x][i];
		}
	}
	return x;
}
void fun(vector<node> &x,int y)
//fun是用来将以root为根的树中，y节点的子树部分的dfn
//这会是几段连续的数字所以 用node中的l,r记录，node中的id没用
//虽然用vector记录但是里面最多有2个node（2段区间就能表示出来）
{
	if(y==root)
	{
		x.push_back(node{1,n,0});
		return ;
	}
	if((dfn[y]<=dfn[root])&&(dfn[root]<=dfn[y]+siz[y]-1))//rt在y子树内就找出要被扣掉的那棵树的根节点son（这里说的x子树为以原来第一遍dfn的默认根 1 建成的树中的x子树）
	{
		//想要找x在包含root的子树里的孩子，不能直接找，要从root往上dep[root]-dep[y]-1层来找
		int tmp=up(root,dep[root]-dep[y]-1);
		if(1<=dfn[tmp]-1) x.push_back(node{1,dfn[tmp]-1,0});//第一个区间
		if(dfn[tmp]+siz[tmp]<=n) x.push_back(node{dfn[tmp]+siz[tmp],n});
		return ;
	}
	x.push_back(node{dfn[y],dfn[y]+siz[y]-1,0});//直接返回根为1时y的子树
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	root=1;
	block=sqrt(m);
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		b[i]=a[i];
	}
	sort(b+1,b+1+n);
	int len=unique(b+1,b+1+n)-b-1;
	for(int i=1;i<n;i++)
	{
		int x,y;
		cin>>x>>y;
		g[x].push_back(y);
		g[y].push_back(x);
	}
	dfs(1,0);
	for(int i=1;i<=n;i++)
	{
		num[dfn[i]]=lower_bound(b+1,b+1+len,a[i])-b;
	}
	while(m--)
	{
		int op,x,y;
		cin>>op>>x;
		if(op==1)
		{
			root=x;
		}
		else
		{
			cin>>y;
			vector<node> vx,vy;
			cnt2++;
			fun(vx,x);
			fun(vy,y);
			for(int i=0;i<vx.size();i++)
			{
				node tmp=vx[i];
				for(int j=0;j<vy.size();j++)
				{
					node tmp2=vy[j];
					add(tmp.l,tmp.r,tmp2.l,tmp2.r,cnt2);
				}
			}
		}
	}
	for(int i=1;i<=qcnt;i++)
	{
		if(q[i].l>q[i].r) swap(q[i].l,q[i].r);
	}
	sort(q+1,q+1+qcnt);
	int L=0,R=0;
	for(int i=1;i<=qcnt;i++)
	{
		int l=q[i].l,r=q[i].r;
		while(L<l)
		{
			sum+=cntr[num[++L]];
			cntl[num[L]]++;
		}
		while(L>l)
		{
			sum-=cntr[num[L]];
			cntl[num[L--]]--;
		}
		while(R<r)
		{
			sum+=cntl[num[++R]];
			cntr[num[R]]++;
		}
		while(R>r)
		{
			sum-=cntl[num[R]];
			cntr[num[R--]]--;
		}
		ans[abs(q[i].id)]+=(sum*((q[i].id>0)?1:-1));
	}
	for(int i=1;i<=cnt2;i++)
	{
		cout<<ans[i]<<"\n";
	}
	return 0;
}
